# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for a team collaboration / project
management platform.  It manages users, projects, tasks, threaded messaging
with attachments, a performance dashboard (completion rate, average
completion time, peer ratings) and exportable reports (CSV / PDF).

The implementation is intentionally dependency-free (Python standard library
only) so it is trivially importable and testable in any environment.  The
code below is organised as several logical "modules"; in a real project each
labelled section would live in its own file.  They are concatenated here into
a single ``solution.py`` deliverable, with the original file name written as a
banner comment above each section.

Design highlights
-----------------
* **Globally unique identifiers** - a single monotonic counter hands out ids
  shared across every entity type, so a user, a project, a task and a message
  never collide.
* **Single shared re-entrant lock** - every store and service shares one
  ``threading.RLock`` exposed as ``manager._lock``.  All public operations are
  serialised through it, guaranteeing consistency under heavy concurrency and
  high load while keeping the locking model simple to reason about.
* **Defensive copies** - all read APIs return deep copies of the stored
  entities, so callers can never mutate internal state by holding onto a
  returned object or list.
* **Explicit, typed error hierarchy** - validation, lookup, authorization,
  duplication and conflict failures each raise a dedicated exception type.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field, replace
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Set, Tuple

__all__ = [
    "TeamCollaborationManager",
    "TaskStatus",
    "UserRole",
    "ReportFormat",
    "ReportType",
    "TeamCollaborationError",
    "ValidationError",
    "NotFoundError",
    "AuthorizationError",
    "DuplicateError",
    "ConflictError",
    "Attachment",
    "User",
    "Project",
    "Task",
    "Message",
    "Rating",
]


# ===========================================================================
# errors.py
# ===========================================================================
class TeamCollaborationError(Exception):
    """Base class for every error raised by the collaboration manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails a business or format validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint (username / email) is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ===========================================================================
# enums.py
# ===========================================================================
class UserRole(Enum):
    """The role a user holds within the platform."""

    MEMBER = "member"
    ADMIN = "admin"
    VIEWER = "viewer"


class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportType(Enum):
    """Kinds of report the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


class ReportFormat(Enum):
    """Supported report export formats."""

    CSV = "csv"
    PDF = "pdf"


# ===========================================================================
# models.py
# ===========================================================================
@dataclass
class User:
    """A registered platform user."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a user, spanning a date range."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work inside a project, optionally assigned to a user."""

    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    """Metadata describing a file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    """A message posted against a project or a task (never both)."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating (1-5) given by one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ===========================================================================
# stores.py  -  in-memory repositories (all share the manager's lock)
# ===========================================================================
class _BaseStore:
    """Common base for entity repositories.

    Every store keeps a reference to the *shared* manager lock so that the
    identity assertion ``id(store._lock) == id(manager._lock)`` holds and all
    mutations are serialised through a single lock.  Methods on the stores
    assume the caller already holds that lock.
    """

    def __init__(self, lock: threading.RLock) -> None:
        self._lock = lock
        self._items: Dict[int, object] = {}

    def get(self, entity_id: int):
        return self._items.get(entity_id)

    def exists(self, entity_id: int) -> bool:
        return entity_id in self._items

    def all_sorted(self) -> List[object]:
        return [self._items[i] for i in sorted(self._items)]


class UserStore(_BaseStore):
    """Stores users and maintains username / email uniqueness indexes."""

    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self._items: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}

    def add(self, user: User) -> None:
        self._items[user.id] = user
        self._by_username[user.username] = user.id
        self._by_email[user.email] = user.id

    def username_owner(self, username: str) -> Optional[int]:
        return self._by_username.get(username)

    def email_owner(self, email: str) -> Optional[int]:
        return self._by_email.get(email)

    def rename(self, user: User, new_username: str) -> None:
        self._by_username.pop(user.username, None)
        user.username = new_username
        self._by_username[new_username] = user.id

    def change_email(self, user: User, new_email: str) -> None:
        self._by_email.pop(user.email, None)
        user.email = new_email
        self._by_email[new_email] = user.id

    def remove(self, user: User) -> None:
        self._items.pop(user.id, None)
        self._by_username.pop(user.username, None)
        self._by_email.pop(user.email, None)


class ProjectStore(_BaseStore):
    """Stores projects."""

    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self._items: Dict[int, Project] = {}

    def add(self, project: Project) -> None:
        self._items[project.id] = project

    def remove(self, project_id: int) -> None:
        self._items.pop(project_id, None)

    def owned_by(self, owner_id: int) -> List[Project]:
        return [p for p in self._items.values() if p.owner_id == owner_id]


class TaskStore(_BaseStore):
    """Stores tasks and maintains by-project and by-assignee indexes."""

    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self._items: Dict[int, Task] = {}
        self._by_project: Dict[int, Set[int]] = {}
        self._by_assignee: Dict[int, Set[int]] = {}

    def add(self, task: Task) -> None:
        self._items[task.id] = task
        self._by_project.setdefault(task.project_id, set()).add(task.id)
        if task.assignee_id is not None:
            self._by_assignee.setdefault(task.assignee_id, set()).add(task.id)

    def set_assignee(self, task: Task, new_assignee_id: Optional[int]) -> None:
        if task.assignee_id is not None:
            bucket = self._by_assignee.get(task.assignee_id)
            if bucket is not None:
                bucket.discard(task.id)
                if not bucket:
                    self._by_assignee.pop(task.assignee_id, None)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self._by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    def remove(self, task: Task) -> None:
        self._items.pop(task.id, None)
        proj_bucket = self._by_project.get(task.project_id)
        if proj_bucket is not None:
            proj_bucket.discard(task.id)
            if not proj_bucket:
                self._by_project.pop(task.project_id, None)
        if task.assignee_id is not None:
            asg_bucket = self._by_assignee.get(task.assignee_id)
            if asg_bucket is not None:
                asg_bucket.discard(task.id)
                if not asg_bucket:
                    self._by_assignee.pop(task.assignee_id, None)

    def for_project(self, project_id: int) -> List[Task]:
        ids = self._by_project.get(project_id, set())
        return [self._items[i] for i in sorted(ids)]

    def for_assignee(self, assignee_id: int) -> List[Task]:
        ids = self._by_assignee.get(assignee_id, set())
        return [self._items[i] for i in sorted(ids)]


class MessageStore(_BaseStore):
    """Stores messages and maintains by-project and by-task indexes."""

    def __init__(self, lock: threading.RLock) -> None:
        super().__init__(lock)
        self._items: Dict[int, Message] = {}
        self._by_project: Dict[int, Set[int]] = {}
        self._by_task: Dict[int, Set[int]] = {}

    def add(self, message: Message) -> None:
        self._items[message.id] = message
        if message.project_id is not None:
            self._by_project.setdefault(message.project_id, set()).add(message.id)
        if message.task_id is not None:
            self._by_task.setdefault(message.task_id, set()).add(message.id)

    def remove(self, message: Message) -> None:
        self._items.pop(message.id, None)
        if message.project_id is not None:
            bucket = self._by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message.id)
                if not bucket:
                    self._by_project.pop(message.project_id, None)
        if message.task_id is not None:
            bucket = self._by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message.id)
                if not bucket:
                    self._by_task.pop(message.task_id, None)

    def for_project(self, project_id: int) -> List[Message]:
        ids = self._by_project.get(project_id, set())
        return [self._items[i] for i in sorted(ids)]

    def for_task(self, task_id: int) -> List[Message]:
        ids = self._by_task.get(task_id, set())
        return [self._items[i] for i in sorted(ids)]


# ===========================================================================
# performance.py  -  ratings + per-user performance metrics
# ===========================================================================
class PerformanceService:
    """Computes completion metrics and manages peer ratings.

    Shares the manager's lock and reaches back into the manager for task and
    user data so all metrics are computed against a consistent snapshot.
    """

    def __init__(self, manager: "TeamCollaborationManager") -> None:
        self._manager = manager
        self._lock = manager._lock
        self._ratings: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, Set[int]] = {}

    # -- internal helpers (assume lock held) -------------------------------
    def _ratings_for(self, ratee_id: int) -> List[Rating]:
        ids = self._by_ratee.get(ratee_id, set())
        return [self._ratings[i] for i in sorted(ids)]

    @staticmethod
    def _completion_time_seconds(task: Task) -> Optional[float]:
        if task.status == TaskStatus.COMPLETED and task.started_at and task.completed_at:
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def _completion_rate(self, tasks: List[Task]) -> float:
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    def _average_completion_time(self, tasks: List[Task]) -> Optional[float]:
        durations = [
            self._completion_time_seconds(t)
            for t in tasks
            if t.status == TaskStatus.COMPLETED
        ]
        durations = [d for d in durations if d is not None]
        if not durations:
            return None
        return sum(durations) / len(durations)

    def _rating_stats(self, ratee_id: int) -> Tuple[int, float]:
        ratings = self._ratings_for(ratee_id)
        if not ratings:
            return 0, 0.0
        return len(ratings), sum(r.score for r in ratings) / len(ratings)

    # -- public API (called via manager delegation) -----------------------
    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._manager._require_user(user_id)
            return self._completion_rate(self._manager.tasks.for_assignee(user_id))

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._manager._require_user(user_id)
            return self._average_completion_time(
                self._manager.tasks.for_assignee(user_id)
            )

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            self._manager._require_user(rater_id)
            self._manager._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("A user cannot rate themselves.")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("Rating score must be an integer.")
            if score < 1 or score > 5:
                raise ValidationError("Rating score must be between 1 and 5.")
            if task_id is not None and not self._manager.tasks.exists(task_id):
                raise NotFoundError("Task {0} not found.".format(task_id))
            rating = Rating(
                id=self._manager._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._manager._clock(),
            )
            self._ratings[rating.id] = rating
            self._by_ratee.setdefault(ratee_id, set()).add(rating.id)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            self._manager._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            self._manager._require_user(user_id)
            tasks = self._manager.tasks.for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
            rating_count, rating_average = self._rating_stats(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }


# ===========================================================================
# reports.py  -  report generation + CSV / PDF export
# ===========================================================================
class ReportService:
    """Builds progress / performance reports and exports them."""

    def __init__(self, manager: "TeamCollaborationManager") -> None:
        self._manager = manager
        self._lock = manager._lock

    # -- report builders ---------------------------------------------------
    def project_progress_report(self, project_id: int) -> dict:
        with self._lock:
            self._manager._require_project(project_id)
            tasks = self._manager.tasks.for_project(project_id)
            now = self._manager._clock()

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    bucket = per_assignee.setdefault(
                        task.assignee_id,
                        {"total_tasks": 0, "completed_tasks": 0},
                    )
                    bucket["total_tasks"] += 1
                    if task.status == TaskStatus.COMPLETED:
                        bucket["completed_tasks"] += 1

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (completed / total) if total else 0.0
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id: Optional[int] = None) -> dict:
        with self._lock:
            if project_id is not None:
                self._manager._require_project(project_id)
                tasks = self._manager.tasks.for_project(project_id)
            else:
                tasks = list(self._manager.tasks._items.values())

            by_user: Dict[int, List[Task]] = {}
            for task in tasks:
                if task.assignee_id is not None:
                    by_user.setdefault(task.assignee_id, []).append(task)

            perf = self._manager.performance
            rows = []
            for user_id in sorted(by_user):
                user_tasks = by_user[user_id]
                user = self._manager.users.get(user_id)
                rating_count, rating_average = perf._rating_stats(user_id)
                rows.append(
                    {
                        "user_id": user_id,
                        "username": user.username if user else None,
                        "total_tasks": len(user_tasks),
                        "completed_tasks": sum(
                            1 for t in user_tasks if t.status == TaskStatus.COMPLETED
                        ),
                        "completion_rate": perf._completion_rate(user_tasks),
                        "average_completion_time": perf._average_completion_time(
                            user_tasks
                        ),
                        "rating_count": rating_count,
                        "rating_average": rating_average,
                    }
                )
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> dict:
        with self._lock:
            self._manager._require_user(user_id)
            perf = self._manager.performance
            tasks = self._manager.tasks.for_assignee(user_id)
            user = self._manager.users.get(user_id)
            rating_count, rating_average = perf._rating_stats(user_id)

            task_rows = [
                {
                    "task_id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "username": user.username if user else None,
                "total_tasks": len(tasks),
                "completed_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                ),
                "in_progress_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
                ),
                "not_started_tasks": sum(
                    1 for t in tasks if t.status == TaskStatus.NOT_STARTED
                ),
                "completion_rate": perf._completion_rate(tasks),
                "average_completion_time": perf._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    # -- export ------------------------------------------------------------
    def export_report(self, report: dict, fmt: ReportFormat):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat enum value.")
        if not isinstance(report, dict):
            raise ValidationError("report must be a report dictionary.")
        if fmt == ReportFormat.CSV:
            return self._to_csv(report)
        if fmt == ReportFormat.PDF:
            return self._to_pdf(report)
        raise ValidationError("Unsupported report format.")  # pragma: no cover

    @staticmethod
    def _stringify(value) -> str:
        if value is None:
            return ""
        if isinstance(value, Enum):
            return str(value.value)
        if isinstance(value, datetime):
            return value.isoformat()
        return str(value)

    def _to_csv(self, report: dict) -> str:
        buf = io.StringIO()
        writer = csv.writer(buf)
        rows = report.get("rows")
        if (
            isinstance(rows, list)
            and rows
            and all(isinstance(r, dict) for r in rows)
        ):
            header: List[str] = []
            for row in rows:
                for key in row:
                    if key not in header:
                        header.append(key)
            writer.writerow(header)
            for row in rows:
                writer.writerow([self._stringify(row.get(key)) for key in header])
        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([key, self._stringify(value)])
        return buf.getvalue()

    def _report_lines(self, report: dict) -> List[str]:
        title = str(report.get("report_type", "report")).replace("_", " ").title()
        lines = [title]
        rows = report.get("rows")
        if isinstance(rows, list) and rows and all(isinstance(r, dict) for r in rows):
            for key, value in report.items():
                if key == "rows":
                    continue
                lines.append("{0}: {1}".format(key, self._stringify(value)))
            lines.append("")
            for idx, row in enumerate(rows, start=1):
                parts = [
                    "{0}={1}".format(k, self._stringify(v)) for k, v in row.items()
                ]
                lines.append("Row {0}: {1}".format(idx, ", ".join(parts)))
        else:
            for key, value in report.items():
                lines.append("{0}: {1}".format(key, self._stringify(value)))
        return lines

    def _to_pdf(self, report: dict) -> bytes:
        return _build_pdf(self._report_lines(report))


def _build_pdf(text_lines: List[str]) -> bytes:
    """Render a minimal but structurally valid single-page PDF document."""

    content_parts = ["BT", "/F1 11 Tf", "50 760 Td", "14 TL"]
    first = True
    for line in text_lines or [""]:
        escaped = (
            str(line)
            .replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )
        if first:
            content_parts.append("({0}) Tj".format(escaped))
            first = False
        else:
            content_parts.append("T*")
            content_parts.append("({0}) Tj".format(escaped))
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
        b"<< /Length "
        + str(len(content)).encode("ascii")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets = []
    for index, obj in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += "{0} 0 obj\n".format(index).encode("ascii")
        pdf += obj
        pdf += b"\nendobj\n"

    xref_pos = len(pdf)
    count = len(objects)
    pdf += "xref\n0 {0}\n".format(count + 1).encode("ascii")
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += "trailer\n<< /Size {0} /Root 1 0 R >>\n".format(count + 1).encode("ascii")
    pdf += "startxref\n{0}\n".format(xref_pos).encode("ascii")
    pdf += b"%%EOF"
    return bytes(pdf)


# ===========================================================================
# manager.py  -  the public facade tying everything together
# ===========================================================================
class TeamCollaborationManager:
    """Thread-safe, in-memory team collaboration backend.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the "current" ``datetime``.
        Injecting a deterministic clock makes timestamp behaviour testable.
        Defaults to :func:`datetime.now`.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._lock = threading.RLock()
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._id_counter = 0

        # Entity stores and services all share the single re-entrant lock.
        self.users = UserStore(self._lock)
        self.projects = ProjectStore(self._lock)
        self.tasks = TaskStore(self._lock)
        self.messages = MessageStore(self._lock)
        self.performance = PerformanceService(self)
        self.reports = ReportService(self)

    # -- internal utilities -----------------------------------------------
    def _next_id(self) -> int:
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    def _clock(self) -> datetime:
        return self._now()

    def _require_user(self, user_id: int) -> User:
        user = self.users.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found.".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found.".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found.".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found.".format(message_id))
        return message

    @staticmethod
    def _validate_email(email: str) -> None:
        if not email or not email.strip() or "@" not in email:
            raise ValidationError("A valid email address is required.")

    # =====================================================================
    # User management
    # =====================================================================
    def register_user(
        self, username: str, email: str, role: UserRole = UserRole.MEMBER
    ) -> User:
        with self._lock:
            if not username or not username.strip():
                raise ValidationError("Username must not be empty.")
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole enum value.")
            if self.users.username_owner(username) is not None:
                raise DuplicateError("Username already in use.")
            if self.users.email_owner(email) is not None:
                raise DuplicateError("Email already in use.")
            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._clock(),
            )
            self.users.add(user)
            return copy.deepcopy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return copy.deepcopy(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [copy.deepcopy(u) for u in self.users.all_sorted()]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self._require_user(user_id)
            if username is not None:
                if not username or not username.strip():
                    raise ValidationError("Username must not be empty.")
                owner = self.users.username_owner(username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("Username already in use.")
            if email is not None:
                self._validate_email(email)
                owner = self.users.email_owner(email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("Email already in use.")
            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole enum value.")

            if username is not None and username != user.username:
                self.users.rename(user, username)
            if email is not None and email != user.email:
                self.users.change_email(user, email)
            if role is not None:
                user.role = role
            return copy.deepcopy(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self._require_user(user_id)
            if self.projects.owned_by(user_id):
                raise ConflictError("User owns one or more projects.")
            assigned = self.tasks.for_assignee(user_id)
            if any(t.status != TaskStatus.COMPLETED for t in assigned):
                raise ConflictError("User has open assigned tasks.")
            # Detach the user from any completed tasks to keep references valid.
            for task in list(assigned):
                self.tasks.set_assignee(task, None)
            self.users.remove(user)

    # =====================================================================
    # Project management
    # =====================================================================
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            if not name or not name.strip():
                raise ValidationError("Project name must not be empty.")
            self._require_user(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date must not be before start_date.")
            project = Project(
                id=self._next_id(),
                name=name,
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._clock(),
            )
            self.projects.add(project)
            return copy.deepcopy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return copy.deepcopy(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [copy.deepcopy(p) for p in self.projects.all_sorted()]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)
            if name is not None and (not name or not name.strip()):
                raise ValidationError("Project name must not be empty.")
            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not be before start_date.")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)
            for task in list(self.tasks.for_project(project_id)):
                for message in list(self.messages.for_task(task.id)):
                    self.messages.remove(message)
                self.tasks.remove(task)
            for message in list(self.messages.for_project(project_id)):
                self.messages.remove(message)
            self.projects.remove(project_id)

    # =====================================================================
    # Task management
    # =====================================================================
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            if not title or not title.strip():
                raise ValidationError("Task title must not be empty.")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("Deadline must not precede project start.")
            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._clock(),
            )
            self.tasks.add(task)
            return copy.deepcopy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return copy.deepcopy(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            return [copy.deepcopy(t) for t in self.tasks.for_project(project_id)]

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            return [copy.deepcopy(t) for t in self.tasks.for_assignee(user_id)]

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self.tasks.set_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self.tasks.set_assignee(task, new_assignee_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self.tasks.set_assignee(task, None)
            return copy.deepcopy(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("Deadline must not precede project start.")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus enum value.")
            now = self._clock()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            elif status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            task.status = status
            return copy.deepcopy(task)

    # =====================================================================
    # Messaging
    # =====================================================================
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)
            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "Exactly one of project_id or task_id must be provided."
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = attachments or []
            has_body = bool(body and body.strip())
            if not has_body and not attachment_specs:
                raise ValidationError(
                    "Message must have a body or at least one attachment."
                )

            now = self._clock()
            built_attachments = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]
            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=now,
                edited_at=None,
            )
            self.messages.add(message)
            return copy.deepcopy(message)

    @staticmethod
    def _build_attachment(
        filename: str, data: bytes, uploaded_by: int, uploaded_at: datetime
    ) -> Attachment:
        if not filename or not filename.strip():
            raise ValidationError("Attachment filename must not be empty.")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=uploaded_at,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("Only the author may edit this message.")
            has_body = bool(new_body and new_body.strip())
            if not has_body and not message.attachments:
                raise ValidationError(
                    "Message must have a body or at least one attachment."
                )
            message.body = new_body
            message.edited_at = self._clock()
            return copy.deepcopy(message)

    def add_attachment(
        self, message_id: int, user_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError(
                    "Only the author may attach files to this message."
                )
            attachment = self._build_attachment(
                filename, data, user_id, self._clock()
            )
            message.attachments.append(attachment)
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            return [copy.deepcopy(m) for m in self.messages.for_project(project_id)]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            return [copy.deepcopy(m) for m in self.messages.for_task(task_id)]

    def delete_message(self, message_id: int, user_id: int) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("Only the author may delete this message.")
            self.messages.remove(message)

    # =====================================================================
    # Performance dashboard (delegated to PerformanceService)
    # =====================================================================
    def get_completion_rate(self, user_id: int) -> float:
        return self.performance.get_completion_rate(user_id)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        return self.performance.get_average_completion_time(user_id)

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        return self.performance.submit_rating(
            rater_id, ratee_id, score, feedback, task_id
        )

    def get_ratings_summary(self, user_id: int) -> dict:
        return self.performance.get_ratings_summary(user_id)

    def get_user_dashboard(self, user_id: int) -> dict:
        return self.performance.get_user_dashboard(user_id)

    # =====================================================================
    # Reports (delegated to ReportService)
    # =====================================================================
    def project_progress_report(self, project_id: int) -> dict:
        return self.reports.project_progress_report(project_id)

    def team_performance_report(self, project_id: Optional[int] = None) -> dict:
        return self.reports.team_performance_report(project_id)

    def individual_performance_report(self, user_id: int) -> dict:
        return self.reports.individual_performance_report(user_id)

    def export_report(self, report: dict, fmt: ReportFormat):
        return self.reports.export_report(report, fmt)


